var ctx = $('Extrair Contexto').first().json;

var lead = null;
try {
  var rows = $('Buscar Lead no CRM').all();
  if (rows.length > 0 && rows[0].json && rows[0].json.Phone) {
    lead = rows[0].json;
  }
} catch(e) { lead = null; }

var catalog = [];
try {
  var catRows = $('Buscar Catalogo RAG').all();
  for (var i = 0; i < catRows.length; i++) {
    if (catRows[i].json && catRows[i].json.Nome) {
      catalog.push(catRows[i].json);
    }
  }
} catch(e) { catalog = []; }

var history = [];
if (lead && lead.ConversationHistory) {
  try {
    var p = JSON.parse(lead.ConversationHistory);
    history = Array.isArray(p) ? p.slice(-20) : [];
  } catch(e) { history = []; }
}

var rawMessage = ctx.message || '';
var currentMessage = rawMessage.length > 2000 ? rawMessage.substring(0, 2000) : rawMessage;

var now = new Date().toISOString();
return [{ json: {
  phone:           ctx.phone,
  instance:        ctx.instance,
  currentMessage:  currentMessage,
  pushName:        ctx.pushName,
  isNewLead:       lead === null,
  name:            (lead && lead.Name)             ? lead.Name            : ctx.pushName,
  company:         (lead && lead.Company)          ? lead.Company         : '',
  cnpj:            (lead && lead.CNPJ)             ? lead.CNPJ            : '',
  email:           (lead && lead.Email)            ? lead.Email           : '',
  stage:           (lead && lead.Stage)            ? lead.Stage           : 'NOVO',
  fitScore:        (lead && lead.FitScore)         ? parseInt(lead.FitScore) : 0,
  productInterest: (lead && lead.ProductInterest)  ? lead.ProductInterest : '',
  budget:          (lead && lead.Budget)           ? lead.Budget          : '',
  createdAt:       (lead && lead.CreatedAt)        ? lead.CreatedAt       : now,
  history:         history,
  catalog:         catalog
}}];

var s = $input.first().json;

var catLines = [];
for (var i = 0; i < s.catalog.length; i++) {
  var p = s.catalog[i];
  var line = '- ' + p.Nome;
  if (p.Descricao)   line = line + ': ' + p.Descricao;
  if (p.Preco)       line = line + ' | R$ ' + p.Preco;
  if (p.PublicoAlvo) line = line + ' | Publico: ' + p.PublicoAlvo;
  catLines.push(line);
}
var catText = catLines.length > 0 ? catLines.join('\n') : 'Catalogo nao configurado. Pergunte a necessidade e informe que consultara detalhes.';

var lgpdNota = s.isNewLead
  ? 'LGPD: No primeiro contato, inclua na apresentacao: "Para melhorar nosso atendimento, armazenamos o historico desta conversa conforme a Lei 13.709/2018 (LGPD). Voce pode solicitar remocao dos dados respondendo REMOVER DADOS."\n\n'
  : '';

var system = 'Voce e Sofia, SDR de IA para o mercado B2B brasileiro.\n'
  + 'Qualifique leads pelo WhatsApp com naturalidade e foco.\n\n'
  + lgpdNota
  + 'ESTAGIO: ' + s.stage + '\n'
  + 'LEAD: ' + s.name + ' | Empresa: ' + (s.company || 'nao informado') + '\n'
  + 'CNPJ: ' + (s.cnpj || 'nao informado') + ' | Email: ' + (s.email || 'nao informado') + '\n'
  + 'Produto interesse: ' + (s.productInterest || 'nao identificado') + '\n'
  + 'Orcamento: ' + (s.budget || 'nao informado') + ' | FitScore: ' + s.fitScore + '/10\n\n'
  + 'CATALOGO DE PRODUTOS:\n' + catText + '\n\n'
  + 'INSTRUCOES:\n'
  + 'NOVO: Apresente-se como Sofia, mencione LGPD conforme nota acima, colete nome e empresa.\n'
  + 'QUALIFICANDO: Use BANT suavizado. Um dado por mensagem.\n'
  + 'PROPOSTA_PENDENTE: Confirme dados e avise que prepara proposta.\n'
  + 'Se o lead disser REMOVER DADOS: responda que o pedido sera processado e defina stage=DESCARTADO.\n\n'
  + 'REGRAS:\n'
  + '1. Responda APENAS em portugues brasileiro natural\n'
  + '2. Maximo 120 palavras por resposta\n'
  + '3. No maximo 1 emoji por mensagem\n'
  + '4. Nao invente informacoes de produtos\n'
  + '5. Se lead mencionar CNPJ de 14 digitos, salve em lead_updates.CNPJ\n'
  + '6. ready_for_proposal=true apenas com nome+empresa+produto+orcamento confirmados\n'
  + '7. FitScore 0-10: 0=descartado 5=morno 8+=quente\n\n'
  + 'RETORNE SOMENTE JSON puro sem markdown:\n'
  + 'chaves: reply stage lead_updates ready_for_proposal reasoning\n'
  + 'lead_updates contem: Name Company CNPJ Email ProductInterest Budget FitScore';

var messages = [{ role: 'system', content: system }];
for (var j = 0; j < s.history.length; j++) {
  messages.push(s.history[j]);
}
messages.push({ role: 'user', content: s.currentMessage });

return [{ json: {
  payload: {
    model: 'gpt-4o',
    max_tokens: 600,
    temperature: 0.5,
    response_format: { type: 'json_object' },
    messages: messages
  },
  session: s
}}];

var session = $('Preparar Prompt IA').first().json.session;
var ai = null;
var parseError = '';

try {
  var raw = $input.first().json;
  if (!raw) throw new Error('resposta vazia');
  if (!raw.choices) throw new Error('sem choices');
  if (!Array.isArray(raw.choices)) throw new Error('choices nao eh array');
  if (raw.choices.length === 0) throw new Error('choices vazio');
  var content = raw.choices[0].message.content;
  if (!content) throw new Error('content vazio');
  if (typeof content !== 'string') throw new Error('content nao string');
  var parsed = JSON.parse(content);
  if (!parsed) throw new Error('parse retornou null');
  if (typeof parsed !== 'object') throw new Error('nao eh objeto');
  if (Array.isArray(parsed)) throw new Error('eh array');
  ai = parsed;
} catch(e) {
  parseError = String(e);
  ai = null;
}

if (ai === null) {
  ai = {
    reply: 'Oi! Tive um probleminha tecnico. Pode repetir? Estou aqui!',
    stage: session.stage,
    lead_updates: {},
    ready_for_proposal: false,
    reasoning: 'erro parse: ' + parseError
  };
}

var reply = (typeof ai.reply === 'string' && ai.reply) ? ai.reply : 'Como posso ajuda-lo?';
var stage = (typeof ai.stage === 'string' && ai.stage) ? ai.stage : session.stage;
var lu = (ai.lead_updates && typeof ai.lead_updates === 'object' && !Array.isArray(ai.lead_updates)) ? ai.lead_updates : {};
var readyForProposal = ai.ready_for_proposal === true;

if (readyForProposal) {
  var chkName    = (lu.Name    && lu.Name    !== 'null') ? lu.Name    : session.name;
  var chkCompany = (lu.Company && lu.Company !== 'null') ? lu.Company : session.company;
  var chkProduct = (lu.ProductInterest && lu.ProductInterest !== 'null') ? lu.ProductInterest : session.productInterest;
  if (!chkName || !chkCompany || !chkProduct) readyForProposal = false;
}

var history = session.history.slice();
history.push({ role: 'user',      content: session.currentMessage });
history.push({ role: 'assistant', content: reply });
if (history.length > 20) history = history.slice(-20);

function pick(a, b) {
  if (a && typeof a === 'string' && a !== 'null') return a;
  return b || '';
}

var fitScoreVal = session.fitScore;
if (lu.FitScore !== null && lu.FitScore !== undefined && lu.FitScore !== 'null') {
  fitScoreVal = lu.FitScore;
}

return [{ json: {
  Phone:               session.phone,
  Name:                pick(lu.Name,            session.name),
  Company:             pick(lu.Company,         session.company),
  CNPJ:                pick(lu.CNPJ,            session.cnpj),
  Email:               pick(lu.Email,           session.email),
  Stage:               stage,
  FitScore:            String(fitScoreVal),
  ProductInterest:     pick(lu.ProductInterest, session.productInterest),
  Budget:              pick(lu.Budget,          session.budget),
  ReadyForProposal:    readyForProposal ? 'SIM' : 'NAO',
  ConversationHistory: JSON.stringify(history),
  CreatedAt:           session.createdAt,
  UpdatedAt:           new Date().toISOString(),
  _reply:              reply,
  _phone:              session.phone,
  _instance:           session.instance
}}];
